import React, { useRef, useEffect, useMemo, Suspense } from "react";
import { Canvas, useFrame } from "@react-three/fiber";
import * as THREE from "three";
import "../style/ThreeHero.css";

/* ═══ 方案一: Particle Data Stream ═══ */
function ParticleField({ mouse }) {
  const ref = useRef();
  const COUNT = 700;

  const { geo, vel } = useMemo(() => {
    const positions = new Float32Array(COUNT * 3);
    const vel = new Float32Array(COUNT * 3);
    for (let i = 0; i < COUNT; i++) {
      positions[i * 3]     = (Math.random() - 0.5) * 14;
      positions[i * 3 + 1] = (Math.random() - 0.5) * 9;
      positions[i * 3 + 2] = (Math.random() - 0.5) * 7;
      vel[i * 3]     = (Math.random() - 0.5) * 0.004;
      vel[i * 3 + 1] = (Math.random() - 0.5) * 0.003;
      vel[i * 3 + 2] = (Math.random() - 0.5) * 0.002;
    }
    const geo = new THREE.BufferGeometry();
    geo.setAttribute("position", new THREE.BufferAttribute(positions, 3));
    return { geo, vel };
  }, []);

  useFrame(() => {
    if (!ref.current) return;
    const pos = ref.current.geometry.attributes.position.array;
    const mx = (mouse.current.x / window.innerWidth) * 6;
    const my = -(mouse.current.y / window.innerHeight) * 4;

    for (let i = 0; i < COUNT; i++) {
      const ix = i * 3, iy = ix + 1, iz = ix + 2;
      pos[ix] += vel[ix]; pos[iy] += vel[iy]; pos[iz] += vel[iz];

      // mouse repulsion
      const dx = pos[ix] - mx, dy = pos[iy] - my;
      const d2 = dx * dx + dy * dy;
      if (d2 < 2.5) {
        const f = 0.012 / (d2 + 0.1);
        pos[ix] += dx * f; pos[iy] += dy * f;
      }

      // wrap boundaries
      if (pos[ix] > 7) pos[ix] = -7; else if (pos[ix] < -7) pos[ix] = 7;
      if (pos[iy] > 4.5) pos[iy] = -4.5; else if (pos[iy] < -4.5) pos[iy] = 4.5;
      if (pos[iz] > 3.5) pos[iz] = -3.5; else if (pos[iz] < -3.5) pos[iz] = 3.5;
    }
    ref.current.geometry.attributes.position.needsUpdate = true;
  });

  return (
    <points ref={ref} geometry={geo}>
      <pointsMaterial color="#C49A7A" size={0.025} transparent opacity={0.45} sizeAttenuation />
    </points>
  );
}

/* ═══ 方案五: Morphing Geometry ═══ */
function MorphingSphere({ mouse }) {
  const ref = useRef();
  const { geo, orig } = useMemo(() => {
    const geo = new THREE.IcosahedronGeometry(0.6, 2);
    const orig = Float32Array.from(geo.attributes.position.array);
    return { geo, orig };
  }, []);

  useFrame(({ clock }) => {
    if (!ref.current) return;
    const t = clock.elapsedTime;
    const arr = ref.current.geometry.attributes.position.array;
    for (let i = 0; i < arr.length; i += 3) {
      const ox = orig[i], oy = orig[i + 1], oz = orig[i + 2];
      const n = Math.sin(ox * 3.2 + t * 0.8) * 0.12
              + Math.cos(oy * 2.5 + t * 0.6) * 0.09
              + Math.sin(oz * 2.8 + t * 0.75) * 0.08;
      arr[i]     = ox * (1 + n);
      arr[i + 1] = oy * (1 + n);
      arr[i + 2] = oz * (1 + n);
    }
    ref.current.geometry.attributes.position.needsUpdate = true;
    ref.current.rotation.y = t * 0.12;
    ref.current.rotation.x = 0.25 + mouse.current.y * 0.00003;
  });

  return (
    <mesh ref={ref} geometry={geo}>
      <meshBasicMaterial color="#D4A574" wireframe transparent opacity={0.22} />
    </mesh>
  );
}

/* ── Orbit rings (unchanged) ── */
function OuterRing({ mouse }) {
  const ref = useRef();
  useFrame(({ clock }) => {
    if (!ref.current) return;
    ref.current.rotation.y = clock.elapsedTime * 0.12;
    ref.current.rotation.x = 0.55 + mouse.current.y * 0.00008;
    ref.current.rotation.z = mouse.current.x * 0.00006;
  });
  return (
    <mesh ref={ref}>
      <torusGeometry args={[2.4, 0.008, 6, 120]} />
      <meshBasicMaterial color="#C49A7A" opacity={0.5} transparent />
    </mesh>
  );
}

function MidRing({ mouse }) {
  const ref = useRef();
  useFrame(({ clock }) => {
    if (!ref.current) return;
    ref.current.rotation.y = -clock.elapsedTime * 0.08;
    ref.current.rotation.x = 1.1 + mouse.current.y * 0.00006;
    ref.current.rotation.z = 0.4 - mouse.current.x * 0.00005;
  });
  return (
    <mesh ref={ref}>
      <torusGeometry args={[1.75, 0.006, 6, 100]} />
      <meshBasicMaterial color="#D4A574" opacity={0.38} transparent />
    </mesh>
  );
}

function InnerRing({ mouse }) {
  const ref = useRef();
  useFrame(({ clock }) => {
    if (!ref.current) return;
    ref.current.rotation.z = clock.elapsedTime * 0.18;
    ref.current.rotation.x = 0.2 + mouse.current.y * 0.00005;
    ref.current.rotation.y = mouse.current.x * 0.00004;
  });
  return (
    <mesh ref={ref}>
      <torusGeometry args={[1.15, 0.005, 6, 80]} />
      <meshBasicMaterial color="#B4846C" opacity={0.3} transparent />
    </mesh>
  );
}

function OrbitDot({ angle, radius, speed }) {
  const ref = useRef();
  const base = useRef(angle);
  useFrame(({ clock }) => {
    if (!ref.current) return;
    const t = clock.elapsedTime * speed + base.current;
    ref.current.position.x = Math.cos(t) * radius;
    ref.current.position.y = Math.sin(t) * radius * 0.35;
    ref.current.position.z = Math.sin(t) * radius * 0.6;
  });
  return (
    <mesh ref={ref}>
      <sphereGeometry args={[0.045, 8, 8]} />
      <meshBasicMaterial color="#B4846C" opacity={0.7} transparent />
    </mesh>
  );
}

const ThreeScene = ({ mouse }) => (
  <>
    <ParticleField mouse={mouse} />
    <MorphingSphere mouse={mouse} />
    <OuterRing mouse={mouse} />
    <MidRing mouse={mouse} />
    <InnerRing mouse={mouse} />
    <OrbitDot angle={0}              radius={2.4} speed={0.14} />
    <OrbitDot angle={Math.PI / 2}   radius={2.4} speed={0.14} />
    <OrbitDot angle={Math.PI}       radius={2.4} speed={0.14} />
    <OrbitDot angle={Math.PI * 1.5} radius={2.4} speed={0.14} />
  </>
);

const ThreeHero = () => {
  const mouse = useRef({ x: 0, y: 0 });

  useEffect(() => {
    const onMove = (e) => {
      mouse.current = {
        x: e.clientX - window.innerWidth / 2,
        y: e.clientY - window.innerHeight / 2,
      };
    };
    window.addEventListener("mousemove", onMove, { passive: true });
    return () => window.removeEventListener("mousemove", onMove);
  }, []);

  return (
    <div className="three-hero-canvas" aria-hidden="true">
      <Canvas camera={{ position: [0, 0, 5], fov: 45 }}>
        <Suspense fallback={null}>
          <ThreeScene mouse={mouse} />
        </Suspense>
      </Canvas>
    </div>
  );
};

export default ThreeHero;
